changeSet.sql:
CREATE TABLE staging.document_chunks (
    tenant_id   TEXT NOT NULL DEFAULT '',
    doc_id      TEXT NOT NULL,
    position    INTEGER NOT NULL,
    chash       TEXT NOT NULL,
    chunk_index INTEGER,
    line_start  INTEGER,
    line_end    INTEGER,
    char_start  INTEGER,
    char_end    INTEGER,
    CONSTRAINT staging_document_chunks_pk PRIMARY KEY (tenant_id, doc_id, position)
);
CREATE TABLE staging.chash_index (
    tenant_id           TEXT NOT NULL DEFAULT '',
    chash               TEXT NOT NULL,
    physical_collection TEXT NOT NULL,
    created_at          TEXT NOT NULL DEFAULT '',
    CONSTRAINT staging_chash_index_pk PRIMARY KEY (tenant_id, chash, physical_collection)
);
CREATE TABLE staging.topic_assignments (
    tenant_id TEXT NOT NULL DEFAULT '',
    doc_id    TEXT NOT NULL,
    topic_id  INTEGER NOT NULL,
    CONSTRAINT staging_topic_assignments_pk PRIMARY KEY (tenant_id, doc_id, topic_id)
);
CREATE TABLE staging.frecency (
    tenant_id      TEXT NOT NULL DEFAULT '',
    chunk_id       TEXT NOT NULL,
    embedded_at    TEXT NOT NULL DEFAULT '',
    ttl_days       INTEGER NOT NULL DEFAULT 0,
    frecency_score DOUBLE PRECISION NOT NULL DEFAULT 0,
    miss_count     INTEGER NOT NULL DEFAULT 0,
    last_hit_at    TEXT NOT NULL DEFAULT '',
    CONSTRAINT staging_frecency_pk PRIMARY KEY (tenant_id, chunk_id)
);
CREATE TABLE staging.relevance_log (
    tenant_id  TEXT NOT NULL DEFAULT '',
    id         BIGINT NOT NULL,
    query      TEXT NOT NULL DEFAULT '',
    chunk_id   TEXT NOT NULL,
    collection TEXT,
    action     TEXT NOT NULL DEFAULT '',
    session_id TEXT,
    ts         TEXT NOT NULL DEFAULT '',
    CONSTRAINT staging_relevance_log_pk PRIMARY KEY (tenant_id, id)
);
CREATE TABLE staging.document_aspects (
    tenant_id              TEXT NOT NULL DEFAULT '',
    doc_id                 TEXT NOT NULL DEFAULT '',
    collection             TEXT NOT NULL DEFAULT '',
    source_path            TEXT NOT NULL DEFAULT '',
    problem_formulation    TEXT,
    proposed_method        TEXT,
    experimental_datasets  TEXT,
    experimental_baselines TEXT,
    experimental_results   TEXT,
    extras                 TEXT,
    confidence             DOUBLE PRECISION,
    extracted_at           TEXT NOT NULL DEFAULT '',
    model_version          TEXT NOT NULL DEFAULT '',
    extractor_name         TEXT NOT NULL DEFAULT '',
    source_uri             TEXT,
    CONSTRAINT staging_document_aspects_pk PRIMARY KEY (tenant_id, collection, source_path)
);
CREATE TABLE staging.aspect_extraction_queue (
    tenant_id       TEXT NOT NULL DEFAULT '',
    collection      TEXT NOT NULL DEFAULT '',
    source_path     TEXT NOT NULL DEFAULT '',
    doc_id          TEXT NOT NULL DEFAULT '',
    content_hash    TEXT NOT NULL DEFAULT '',
    content         TEXT NOT NULL DEFAULT '',
    status          TEXT NOT NULL DEFAULT 'pending',
    retry_count     INTEGER NOT NULL DEFAULT 0,
    enqueued_at     TEXT NOT NULL DEFAULT '',
    last_attempt_at TEXT,
    last_error      TEXT,
    CONSTRAINT staging_aspect_queue_pk PRIMARY KEY (tenant_id, collection, source_path)
);
ALTER TABLE staging.document_chunks ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.document_chunks FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.document_chunks
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.chash_index ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.chash_index FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.chash_index
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.topic_assignments ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.topic_assignments FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.topic_assignments
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.frecency ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.frecency FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.frecency
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.relevance_log ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.relevance_log FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.relevance_log
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.document_aspects ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.document_aspects FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.document_aspects
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));
ALTER TABLE staging.aspect_extraction_queue ENABLE ROW LEVEL SECURITY;
ALTER TABLE staging.aspect_extraction_queue FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON staging.aspect_extraction_queue
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP TABLE IF EXISTS staging.aspect_extraction_queue;
DROP TABLE IF EXISTS staging.document_aspects;
DROP TABLE IF EXISTS staging.relevance_log;
DROP TABLE IF EXISTS staging.frecency;
DROP TABLE IF EXISTS staging.topic_assignments;
DROP TABLE IF EXISTS staging.chash_index;
DROP TABLE IF EXISTS staging.document_chunks;
